/**
 * Bootstrap script for the knotgraft fabric server.
 *
 * Opens three transports simultaneously and keeps them alive until
 * SIGINT/SIGTERM:
 *
 *   HTTP (default :7801)  — POST raw bytes to `/ingest`
 *   TCP  (default :4244)  — length-prefixed Aeon FlowFrames
 *   UDP  (default :4245)  — one FlowFrame per datagram
 *
 * Config via env:
 *   KNOTGRAFT_HTTP_PORT      (default 7801)
 *   KNOTGRAFT_TCP_PORT       (default 4244)
 *   KNOTGRAFT_UDP_PORT       (default 4245)
 *   KNOTGRAFT_TENANT_HI      (default 0x1234_5678)
 *   KNOTGRAFT_TENANT_LO      (default 0x9abc_def0)
 *   KNOTGRAFT_AUTH_TOKEN     (optional; if set, HTTP enforces Bearer)
 *   KNOTGRAFT_LANE_COUNT     (default 16)
 *   KNOTGRAFT_EMIT_SQL       (default false; set `true` to default to SQL emission)
 *   KNOTGRAFT_MAX_BYTES      (default 67108864 = 64 MB; HTTP/TCP cap)
 *   KNOTGRAFT_UDP_MAX_BYTES  (default 1400; conservative MTU)
 *
 * Usage:
 *   node ./bin/gnode.js run scripts/run-knotgraft-fabric.ts
 */

import { startKnotgraftFabric } from '../src/knotgraft-fabric-server';

function envInt(name: string, fallback: number): number {
  const raw = process.env[name];
  if (!raw) return fallback;
  const n = Number(raw);
  return Number.isFinite(n) ? n : fallback;
}

function envBool(name: string, fallback: boolean): boolean {
  const raw = process.env[name];
  if (!raw) return fallback;
  return raw.toLowerCase() === 'true' || raw === '1' || raw.toLowerCase() === 'yes';
}

async function main() {
  const handle = await startKnotgraftFabric({
    httpPort: envInt('KNOTGRAFT_HTTP_PORT', 7801),
    flowTcpPort: envInt('KNOTGRAFT_TCP_PORT', 4244),
    flowUdpPort: envInt('KNOTGRAFT_UDP_PORT', 4245),
    defaultTenant: {
      hi: envInt('KNOTGRAFT_TENANT_HI', 0x1234_5678),
      lo: envInt('KNOTGRAFT_TENANT_LO', 0x9abc_def0),
    },
    authToken: process.env['KNOTGRAFT_AUTH_TOKEN'] ?? undefined,
    laneCount: envInt('KNOTGRAFT_LANE_COUNT', 16),
    emitSql: envBool('KNOTGRAFT_EMIT_SQL', false),
    maxRequestBytes: envInt('KNOTGRAFT_MAX_BYTES', 64 * 1024 * 1024),
    maxUdpPayloadBytes: envInt('KNOTGRAFT_UDP_MAX_BYTES', 1400),
  });

  console.log('[knotgraft-fabric] all three transports up:');
  console.log(`  HTTP:     :${handle.httpPort}`);
  console.log(`  TCP Flow: :${handle.flowTcpPort ?? 'disabled'}`);
  console.log(`  UDP Flow: :${handle.flowUdpPort ?? 'disabled'}`);
  console.log('');
  console.log('Formal anchor: ForkRaceFoldTheorems/PrismaticRefraction.lean');
  console.log('Crown theorem: THM-WIRE-TO-STORAGE-IS-SOUND');
  console.log('');
  console.log('  HTTP ingest:  curl -X POST -H "content-type: application/octet-stream" --data-binary @file.bin http://localhost:7801/ingest');
  console.log('  HTTP info:    curl http://localhost:7801/');
  console.log('');
  console.log('Press Ctrl+C to stop.');

  const shutdown = async (signal: string) => {
    console.log(`[knotgraft-fabric] ${signal} — shutting down...`);
    await handle.close();
    process.exit(0);
  };
  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('SIGTERM', () => shutdown('SIGTERM'));
}

main().catch((err) => {
  console.error('[knotgraft-fabric] fatal:', err);
  process.exit(1);
});
